import{c as t,Q as a,j as s,m as n}from"./chunks/framework.BXc4yaFE.js";const d=JSON.parse('{"title":"Latent State Estimation Helps UI Agents to Reason","description":"","frontmatter":{"title":"Latent State Estimation Helps UI Agents to Reason","arxiv_id":"2405.11120","authors":"William E Bishop, Alice Li, Christopher Rawles, Oriana Riva","published":"2024-05-17","source":"https://arxiv.org/abs/2405.11120","venue":"arXiv"},"headers":[],"relativePath":"research/papers/2024-05-17-latent-state-estimation-ui-agents-2405.11120.md","filePath":"research/papers/2024-05-17-latent-state-estimation-ui-agents-2405.11120.md","lastUpdated":1779920788000}'),o={name:"research/papers/2024-05-17-latent-state-estimation-ui-agents-2405.11120.md"};function i(r,e,h,c,l,p){return a(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="latent-state-estimation-helps-ui-agents-to-reason" tabindex="-1">Latent State Estimation Helps UI Agents to Reason <a class="header-anchor" href="#latent-state-estimation-helps-ui-agents-to-reason" aria-label="Permalink to &quot;Latent State Estimation Helps UI Agents to Reason&quot;">​</a></h1><p><strong>Authors</strong>: William E Bishop, Alice Li, Christopher Rawles, Oriana Riva</p><p><strong>Published</strong>: May 17, 2024</p><p><strong>Source</strong>: <a href="https://arxiv.org/abs/2405.11120" target="_blank" rel="noreferrer">https://arxiv.org/abs/2405.11120</a></p><p><strong>Subject Classification</strong>: Artificial Intelligence (cs.AI); Machine Learning (cs.LG)</p><p><strong>License</strong>: Creative Commons BY 4.0</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>The research explores whether large language models can estimate and reason about latent environmental state—aspects of a task environment that are uncertain or obscured. The investigators focused on autonomous UI agents operating in real-world settings where &quot;the response of an environment to their actions may be non-deterministic and observed through noise.&quot;</p><p>The team demonstrated that appropriately prompted LLMs achieve over 76% accuracy when estimating latent state aspects like actual versus intended actions and task completion status. Across multiple benchmarks and reasoning approaches, agents employing explicit latent state estimation &quot;are able to successfully complete up to 1.6x more tasks than those that do not.&quot;</p><hr><h2 id="core-contribution" tabindex="-1">Core Contribution <a class="header-anchor" href="#core-contribution" aria-label="Permalink to &quot;Core Contribution&quot;">​</a></h2><p>This research demonstrates that LLMs can estimate hidden aspects of UI state—such as performed actions, screen summaries, task progression, mistakes, and completion status—despite noisy and partial screen representations. The paper shows incorporating these latent state estimates improves UI agent task success rates by up to 1.6x.</p><hr><h2 id="key-findings" tabindex="-1">Key Findings <a class="header-anchor" href="#key-findings" aria-label="Permalink to &quot;Key Findings&quot;">​</a></h2><h3 id="latent-state-estimation-accuracy" tabindex="-1">Latent State Estimation Accuracy <a class="header-anchor" href="#latent-state-estimation-accuracy" aria-label="Permalink to &quot;Latent State Estimation Accuracy&quot;">​</a></h3><p>The LLM achieved high accuracy across five state aspects, ranging from &quot;76.8%–97.3%&quot; depending on the aspect. Performance matched or exceeded human experts on most measures, particularly for inferring task progression.</p><h3 id="performance-improvements" tabindex="-1">Performance Improvements <a class="header-anchor" href="#performance-improvements" aria-label="Permalink to &quot;Performance Improvements&quot;">​</a></h3><p>When agents explicitly reasoned about latent state, task success increased substantially:</p><ul><li>Zero-shot: 28.1% → 45.9%</li><li>CoT-SC: 28.1% → 42.2%</li><li>ReAct: 35.6% → 43.7%</li></ul><h3 id="evaluation-methodology" tabindex="-1">Evaluation Methodology <a class="header-anchor" href="#evaluation-methodology" aria-label="Permalink to &quot;Evaluation Methodology&quot;">​</a></h3><p>The work uniquely emphasizes online end-to-end testing rather than offline pre-recorded data, using three Android benchmarks totaling 135 tasks across 48 apps.</p><hr><h2 id="technical-approach" tabindex="-1">Technical Approach <a class="header-anchor" href="#technical-approach" aria-label="Permalink to &quot;Technical Approach&quot;">​</a></h2><p>The method formalizes latent state estimation as calculating &quot;point estimates...from noisy observations&quot; by prompting LLMs to infer hidden variables through zero-shot reasoning. Estimates chain together—earlier inferences inform later ones—without requiring task-specific training data.</p><h3 id="zero-shot-reasoning-method" tabindex="-1">Zero-Shot Reasoning Method <a class="header-anchor" href="#zero-shot-reasoning-method" aria-label="Permalink to &quot;Zero-Shot Reasoning Method&quot;">​</a></h3><p>The approach relies on:</p><ul><li>Zero-shot prompting functioning as point estimation in textual space</li><li>Chain-of-thought with self-consistency for enhanced reasoning</li><li>ReAct approaches for integrated act-reason integration</li></ul><hr><h2 id="significance" tabindex="-1">Significance <a class="header-anchor" href="#significance" aria-label="Permalink to &quot;Significance&quot;">​</a></h2><p>This work bridges reasoning methodology and content: showing that <em>what</em> LLMs reason about (latent state) matters as much as <em>how</em> they reason, with benefits consistent across multiple reasoning approaches.</p>',31)])])}const u=t(o,[["render",i]]);export{d as __pageData,u as default};
